試作：
X1 年 1 月至10 月間各交易分錄。（10分）
若 X1 年本期淨利為$87,800，計算每股股東權益、每股盈餘。（10 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:44+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "414", "s": "0803", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00008', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-114-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '下列那一項調整事項屬於應付費用，且應作會計分錄處理？', '["年底有尚未收現的利息收入$4,500", "年底有尚未付款的租金支出$6,000", "年初已提前支付三年的保險費$1,200", "年初購置設備，估計設備每月折舊費用為$8,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:44+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "414", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00009', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-114-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司為客戶維修電腦，並在完成後寄發帳單，客戶尚未付款。下列那一項是甲公司之正確會計 處理？', '["應收帳款增加", "權益增加", "暫不入帳", "選項"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:44+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "414", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00010', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-114-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司於X1年1月1日簽訂一份租期為3年的設備租賃合約，租金每年期末支付$100,000。該 設備的經濟使用年限為5年。公司依據IFRS16判定本租賃為使用權資產並採用負債現值，折現 率6%。請問：甲公司對此租賃合約的會計處理，何者正確？', '["使用權資產初始金額應等於租賃負債之現值，後續按5年提列折舊", "使用權資產初始金額應等於租賃負債之現值，後續按3年提列折舊", "使用權資產初始金額應以租賃期間租金總額為基礎，後續按5年提列折舊", "使用權資產初始金額應以租金總額為基礎，並不需考慮提列折舊"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:44+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "414", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00011', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-114-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '以下為甲公司於 X1 年底資產負債表所揭露的資訊：存貨報導金額為$90（包含原始成本$100 與 備抵存貨跌價損失$10）。至 X2 年末，甲公司存貨的原始成本為$120，淨變現價值為$140。下列 關於X2 年的會計處理與資訊揭露，何者正確？', '["X2年應認列回升利益$30，並將存貨報導為$120", "X2年應認列回升利益$10，並將存貨報導為$130", "X2年應認列回升利益$10，並將存貨報導為$120", "X2年應認列回升利益$30，並將存貨報導為$130"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:44+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "414", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00012', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-114-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', 'A公司期末調整前應付利息為$0，預收收入為$24,000；經調整後，應付利息為$6,000，預收收入 為$16,000。此兩項調整對本期淨利的影響為何？', '["淨利增加$2,000", "淨利減少$2,000", "淨利增加$6,000", "淨利增加$8,000 41430"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:44+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "414", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00013', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-114-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司於2025年1月5日收到一張帳單，內容為2024年12月的廣告費用$12,000，預計將於1 月10日付款。請問甲公司應於那一年度認列此筆費用？', '["2024年", "2025年", "2024或2025年皆可", "不需認列，直到付款為止"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:44+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "414", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00014', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-114-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', 'A公司採永續盤存制。某日賒銷並寄出商品給B公司，售價為$15,000，成本為$8,000，交貨條件 為目的地交貨。假設貨物隔日才送達，請問下列那一個分錄正確反映賒銷並寄出商品當日與存貨 相關的會計處理？', '["借：銷貨成本8,000；貸：存貨8,000", "借：進貨8,000；貸：銷貨成本8,000", "借：銷貨成本8,000；貸：進貨8,000", "無需作任何與存貨有關的分錄"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:44+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "414", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00015', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-114-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司於X5年5月1日購入一台機器，定價為$250,000，議定以九五折成交，付款條件為1/10,n/30， 且公司於折扣期限內全額付款。此外，公司另支出安裝費用$5,000，機器試車費用$3,000，機器於 安裝時發生損壞，修理費用$2,200。請問該機器的入帳成本為多少？', '["$235,125", "$240,125", "$243,125", "$245,325"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:44+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "414", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00016', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-114-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司於X1年年初以$10,000投資取得乙公司40%的普通股，並對乙公司具有重大影響，因此採 用權益法進行會計處理。X1年度乙公司淨利為$1,000，並宣告發放現金股利$500。該投資無需攤 銷差額。請問：甲公司於X1年度應認列之投資收益金額、股利收入金額與X1年底投資帳面金額 分別為何？', '["投資收益為$400，股利收入為$0，期末投資帳面金額為 $10,200", "投資收益為$400，股利收入為$200，期末投資帳面金額為$10,600", "投資收益為$200，股利收入為$200，期末投資帳面金額為$10,200", "投資收益為$200，股利收入為$0，期末投資帳面金額為$10,400"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:44+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "414", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL)
